const item = $input.first();

// Filename is in json, not binary
// Key: "Upload Invoice Here" → array → first item → filename
const formData = item.json?.['Upload Invoice Here'];
const fileInfo = Array.isArray(formData) 
  ? formData[0] 
  : formData;

const fileName = 
  fileInfo?.filename ||
  fileInfo?.fileName ||
  "unknown.pdf";

const docId = fileName
  .replace(/\.pdf$/i, "")
  .toUpperCase()
  .replace(/\s+/g, "-");

// Binary is stored under "Upload_Invoice_Here" key
const binaryData = item.binary?.['Upload_Invoice_Here'];

return [{
  json: {
    doc_id:      docId,
    file_name:   fileName,
    uploaded_at: new Date().toISOString()
  },
  binary: {
    data: binaryData
  }
}];

