const item = $input.first();

// Extract result comes as stringified JSON
let extracted = {};
try {
  const raw = item.json.result || '{}';
  extracted = JSON.parse(raw);
} catch(e) {
  extracted = {};
}

// Calculate days until deadline
let daysLeft = 999;
try {
  const deadlineStr = extracted.submission_deadline || '';
  const deadline = new Date(deadlineStr);
  const today = new Date();
  if (!isNaN(deadline)) {
    daysLeft = Math.floor((deadline - today) / (1000 * 60 * 60 * 24));
  }
} catch(e) {}

// Bid scoring
let score = 5;
let flags = [];

if (daysLeft > 7)  { score += 2; }
if (daysLeft >= 0 && daysLeft < 3) { score -= 3; flags.push("⚠️ Deadline very tight"); }
if (daysLeft < 0)  { score = 0; flags.push("❌ Deadline passed"); }

const insurance = Number(extracted.insurance_gl_amount) || 0;
if (insurance > 0 && insurance <= 5000000) { score += 1; }
if (insurance > 10000000) { score -= 1; flags.push("⚠️ High insurance"); }
if (!extracted.bond_required) { score += 1; }

score = Math.min(10, Math.max(0, score));

let recommendation = '';
if (score >= 7)      { recommendation = '✅ BID'; }
else if (score >= 4) { recommendation = '⚠️ REVIEW'; }
else                 { recommendation = '❌ SKIP'; }

return [{
  json: {
    rft_number:          extracted.rft_number || '',
    project_title:       extracted.project_title || '',
    issuing_authority:   extracted.issuing_authority || '',
    contact_name:        extracted.contact_name || '',
    contact_email:       extracted.contact_email || '',
    contact_phone:       extracted.contact_phone || '',
    submission_deadline: extracted.submission_deadline || '',
    questions_deadline:  extracted.questions_deadline || '',
    award_date:          extracted.award_date || '',
    delivery_date:       extracted.delivery_date || '',
    insurance_gl:        extracted.insurance_gl_amount || '',
    wsib_required:       extracted.wsib_required || false,
    bond_required:       extracted.bond_required || false,
    bond_percentage:     extracted.bond_percentage || 0,
    award_basis:         extracted.award_basis || '',
    irrevocability_days: extracted.irrevocability_days || 90,
    days_until_deadline: daysLeft,
    bid_score:           score,
    recommendation:      recommendation,
    flags:               flags.join(', '),
    status:              'New',
    rag_status:          'Pending'
  }
}];

