const item = $input.first();

const fullText  = item.json.full_text || '';
const segments  = item.json.segments || [];
const doc_id    = item.json.doc_id || '';
const fileName  = item.json.file_name || '';

// Split full text by page number markers
// LlamaParse embeds <page_number>N</page_number> tags
const pagePattern = /<page_number>(\d+)<\/page_number>/gi;
const pageTexts   = {};

let lastPage    = 1;
let lastIndex   = 0;
let match;

// Find all page markers and extract text per page
const allMatches = [...fullText.matchAll(/<page_number>(\d+)<\/page_number>/gi)];

allMatches.forEach((m, idx) => {
  const pageNum  = parseInt(m[1]);
  const startIdx = lastIndex;
  const endIdx   = m.index;

  if (!pageTexts[lastPage]) pageTexts[lastPage] = '';
  pageTexts[lastPage] += fullText.slice(startIdx, endIdx);

  lastPage  = pageNum;
  lastIndex = m.index + m[0].length;
});

// Add remaining text after last marker
if (!pageTexts[lastPage]) pageTexts[lastPage] = '';
pageTexts[lastPage] += fullText.slice(lastIndex);

// Now carve text per segment using EXACT page content
const results = [];

segments.forEach((seg) => {
  const pages = seg.pages || [];
  if (pages.length === 0) return;

  // Get exact text for these pages
  let sectionText = pages
    .map(p => pageTexts[p] || '')
    .join('\n\n')
    .trim();

  if (sectionText.length < 30) return;

  // Semantic chunking by paragraph
  const paragraphs = sectionText
    .split(/\n\n+/)
    .map(p => p.trim())
    .filter(p => p.length > 30);

  const maxChunkSize = 600;
  let currentChunk   = '';
  let chunkIndex     = 0;

  paragraphs.forEach((para) => {
    if (currentChunk.length > 0 &&
        (currentChunk + '\n\n' + para).length > maxChunkSize) {
      results.push({
        json: {
          doc_id,
          file_name:   fileName,
          section:     seg.category,
          chunk_index: chunkIndex,
          chunk_text:  currentChunk,
          page_ref:    pages.join(', '),
          uploaded_at: new Date().toISOString()
        }
      });
      chunkIndex++;
      currentChunk = para;
    } else {
      currentChunk = currentChunk
        ? currentChunk + '\n\n' + para
        : para;
    }
  });

  if (currentChunk.length > 30) {
    results.push({
      json: {
        doc_id,
        file_name:   fileName,
        section:     seg.category,
        chunk_index: chunkIndex,
        chunk_text:  currentChunk,
        page_ref:    pages.join(', '),
        uploaded_at: new Date().toISOString()
      }
    });
  }
});

return results;

const item = $input.first();

// Chat trigger sends message in chatInput field
const question = item.json?.chatInput ||
                 item.json?.message?.text ||
                 item.json?.input || '';

// ⚠️ CONFIGURE ME
