const docId = 'YOUR_DOC_ID_HERE';

return [{
  json: {
    question: question,
    doc_id:   docId
  }
}];

const items = $input.all();

// Build context from top 3 chunks
const contextParts = items.map((item, idx) => {
  const section   = item.json.section || 'unknown';
  const chunkText = item.json.chunk_text || '';
  const similarity = item.json.similarity || 0;
  return `[Source ${idx + 1} — Section: ${section} | Similarity: ${Math.round(similarity * 100)}%]:\n${chunkText}`;
});

const context = contextParts.join('\n\n---\n\n');
const sources = [...new Set(items.map(i => i.json.section))].join(', ');

// Get original question
const question = $('Extract Question').first().json.question;
const docId    = $('Extract Question').first().json.doc_id;

return [{
  json: {
    context,
    sources,
    question,
    doc_id: docId
  }
}];

const item = $input.first();

let answer = '';

// DeepSeek is returning content directly at top level
// not nested inside choices[0].message.content
const content = item.json?.content || 
                item.json?.choices?.[0]?.message?.content;

if (typeof content === 'string') {
  answer = content;
} else if (Array.isArray(content)) {
  // Find text block — skip thinking blocks
  const textBlock = content.find(b => b.type === 'text');
  answer = textBlock?.text || '';
} else {
  answer = 'Sorry, could not generate an answer.';
}

const sources = $('Build Context').first().json.sources;

return [{
  json: {
    output: `${answer}\n\n📄 *Sources: ${sources}*`
  }
}];
